(window.webpackJsonp=window.webpackJsonp||[]).push([[289],{916:function(n,r){n.exports='\x3c!-- \r\ntitle: VsCode\r\nsort: \r\n--\x3e \r\n# VsCode配置\r\n\r\n## 基本\r\n\r\n- `.vscode`中存着配置文件\r\n\r\n- 正则表达式搜索\r\n\r\n  > 搜索: `code.(.*).fzf`\r\n  >\r\n  > 替换:  `code.$1.fzf`\r\n\r\n## 配置\r\n\r\n- **同步github**\r\n\r\n  > 在vs控制台输入：\r\n  >\r\n  > `git config --global user.name "fzf"`\r\n  >\r\n  > `git config --global user.email "nmdfzf404@163.com"`\r\n  >\r\n  > 接着初始化git：\r\n  >\r\n  > `git init`\r\n  >\r\n  > 新建密钥：\r\n  >\r\n  > `ssh-keygen.exe`\r\n  >\r\n  > 复制`id_rsa.pub`到Delpoy keys\r\n\r\n- 自己配置快捷键\r\n\r\n  `Ctrl+K S`\r\n\r\n## ==问题==\r\n\r\n> RemoteSSH\r\n>\r\n> 连接报错\r\n>\r\n> 在这写.ssh/config\r\n\r\n![image-20201122222158054](https://gitee.com//nmdfzf404/Image-hosting/raw/master/2020/image-20201122222158054.png)\r\n\r\n> CodeRunner乱码\r\n>\r\n> 进入setting.json，添加如下字段：\r\n>\r\n> `"code-runner.runInTerminal": true`\r\n\r\n## 插件推荐\r\n\r\n- `KoroFileHeader`\r\n\r\n  > `ctrl+alt+i`: 文件注释\r\n  >\r\n  > `ctrl+alt+t`: 函数注释\r\n'}}]);